1	//! The global data and participant for garbage collection.
2	//!
3	//! # Registration
4	//!
5	//! In order to track all participants in one place, we need some form of participant
6	//! registration. When a participant is created, it is registered to a global lock-free
7	//! singly-linked list of registries; and when a participant is leaving, it is unregistered from the
8	//! list.
9	//!
10	//! # Pinning
11	//!
12	//! Every participant contains an integer that tells whether the participant is pinned and if so,
13	//! what was the global epoch at the time it was pinned. Participants also hold a pin counter that
14	//! aids in periodic global epoch advancement.
15	//!
16	//! When a participant is pinned, a `Guard` is returned as a witness that the participant is pinned.
17	//! Guards are necessary for performing atomic operations, and for freeing/dropping locations.
18	//!
19	//! # Thread-local bag
20	//!
21	//! Objects that get unlinked from concurrent data structures must be stashed away until the global
22	//! epoch sufficiently advances so that they become safe for destruction. Pointers to such objects
23	//! are pushed into a thread-local bag, and when it becomes full, the bag is marked with the current
24	//! global epoch and pushed into the global queue of bags. We store objects in thread-local storages
25	//! for amortizing the synchronization cost of pushing the garbages to a global queue.
26	//!
27	//! # Global queue
28	//!
29	//! Whenever a bag is pushed into a queue, the objects in some bags in the queue are collected and
30	//! destroyed along the way. This design reduces contention on data structures. The global queue
31	//! cannot be explicitly accessed: the only way to interact with it is by calling functions
32	//! `defer()` that adds an object to the thread-local bag, or `collect()` that manually triggers
33	//! garbage collection.
34	//!
35	//! Ideally each instance of concurrent data structure may have its own queue that gets fully
36	//! destroyed as soon as the data structure gets dropped.
37	
38	use core::{
39	    cell::Cell,
40	    fmt,
41	    mem::{self, ManuallyDrop},
42	    num::Wrapping,
43	    ptr,
44	};
45	
46	use crossbeam_utils::CachePadded;
47	
48	use crate::{
49	    atomic::{Owned, Shared},
50	    collector::{Collector, LocalHandle},
51	    deferred::Deferred,
52	    epoch::{AtomicEpoch, Epoch},
53	    guard::{Guard, unprotected},
54	    primitive::{
55	        cell::UnsafeCell,
56	        sync::atomic::{self, Ordering},
57	    },
58	    sync::{
59	        list::{Entry, IsElement, IterError, List},
60	        queue::Queue,
61	    },
62	};
63	
64	/// Maximum number of objects a bag can contain.
65	#[cfg(not(any(crossbeam_sanitize, miri)))]
66	const MAX_OBJECTS: usize = 64;
67	// Makes it more likely to trigger any potential data races.
68	#[cfg(any(crossbeam_sanitize, miri))]
69	const MAX_OBJECTS: usize = 4;
70	
71	/// A bag of deferred functions.
72	pub(crate) struct Bag {
73	    /// Stashed objects.
74	    deferreds: [Deferred; MAX_OBJECTS],
75	    len: usize,
76	}
77	
78	/// `Bag::try_push()` requires that it is safe for another thread to execute the given functions.
79	unsafe impl Send for Bag {}
80	
81	impl Bag {
82	    /// Returns a new, empty bag.
83	    pub(crate) fn new() -> Self {
84	        Self::default()
85	    }
86	
87	    /// Returns `true` if the bag is empty.
88	    pub(crate) fn is_empty(&self) -> bool {
89	        self.len == 0
90	    }
91	
92	    /// Attempts to insert a deferred function into the bag.
93	    ///
94	    /// Returns `Ok(())` if successful, and `Err(deferred)` for the given `deferred` if the bag is
95	    /// full.
96	    ///
97	    /// # Safety
98	    ///
99	    /// It should be safe for another thread to execute the given function.
100	    pub(crate) unsafe fn try_push(&mut self, deferred: Deferred) -> Result<(), Deferred> {
101	        if self.len < MAX_OBJECTS {
102	            self.deferreds[self.len] = deferred;
103	            self.len += 1;
104	            Ok(())
105	        } else {
106	            Err(deferred)
107	        }
108	    }
109	
110	    /// Seals the bag with the given epoch.
111	    fn seal(self, epoch: Epoch) -> SealedBag {
112	        SealedBag { epoch, _bag: self }
113	    }
114	}
115	
116	impl Default for Bag {
117	    fn default() -> Self {
118	        Self {
119	            len: 0,
120	            deferreds: [Deferred::NO_OP; MAX_OBJECTS],
121	        }
122	    }
123	}
124	
125	impl Drop for Bag {
126	    fn drop(&mut self) {
127	        // Call all deferred functions.
128	        for deferred in &mut self.deferreds[..self.len] {
129	            let no_op = Deferred::NO_OP;
130	            let owned_deferred = mem::replace(deferred, no_op);
131	            owned_deferred.call();
132	        }
133	    }
134	}
