1	use alloc::boxed::Box;
2	use core::{
3	    fmt,
4	    marker::PhantomData,
5	    mem::{self, MaybeUninit},
6	    ptr,
7	};
8	
9	/// Number of words a piece of `Data` can hold.
10	///
11	/// Three words should be enough for the majority of cases. For example, you can fit inside it the
12	/// function pointer together with a fat pointer representing an object that needs to be destroyed.
13	const DATA_WORDS: usize = 3;
14	
15	/// Some space to keep a `FnOnce()` object on the stack.
16	type Data = [usize; DATA_WORDS];
17	
18	/// A `FnOnce()` that is stored inline if small, or otherwise boxed on the heap.
19	///
20	/// This is a handy way of keeping an unsized `FnOnce()` within a sized structure.
21	pub(crate) struct Deferred {
22	    call: unsafe fn(*mut u8),
23	    data: MaybeUninit<Data>,
24	    _marker: PhantomData<*mut ()>, // !Send + !Sync
25	}
26	
27	impl fmt::Debug for Deferred {
28	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> Result<(), fmt::Error> {
29	        f.pad("Deferred { .. }")
30	    }
31	}
32	
33	impl Deferred {
34	    pub(crate) const NO_OP: Self = {
35	        fn no_op_call(_raw: *mut u8) {}
36	        Self {
37	            call: no_op_call,
38	            data: MaybeUninit::uninit(),
39	            _marker: PhantomData,
40	        }
41	    };
42	
43	    /// Constructs a new `Deferred` from a `FnOnce()`.
44	    pub(crate) fn new<F: FnOnce()>(f: F) -> Self {
45	        let size = mem::size_of::<F>();
46	        let align = mem::align_of::<F>();
47	
48	        unsafe {
49	            if size <= mem::size_of::<Data>() && align <= mem::align_of::<Data>() {
50	                let mut data = MaybeUninit::<Data>::uninit();
51	                ptr::write(data.as_mut_ptr().cast::<F>(), f);
52	
53	                unsafe fn call<F: FnOnce()>(raw: *mut u8) {
54	                    let f: F = unsafe { ptr::read(raw.cast::<F>()) };
55	                    f();
56	                }
57	
58	                Self {
59	                    call: call::<F>,
60	                    data,
61	                    _marker: PhantomData,
62	                }
63	            } else {
64	                let b: Box<F> = Box::new(f);
65	                let mut data = MaybeUninit::<Data>::uninit();
66	                ptr::write(data.as_mut_ptr().cast::<Box<F>>(), b);
67	
68	                unsafe fn call<F: FnOnce()>(raw: *mut u8) {
69	                    // It's safe to cast `raw` from `*mut u8` to `*mut Box<F>`, because `raw` is
70	                    // originally derived from `*mut Box<F>`.
71	                    let b: Box<F> = unsafe { ptr::read(raw.cast::<Box<F>>()) };
72	                    (*b)();
73	                }
74	
75	                Self {
76	                    call: call::<F>,
77	                    data,
78	                    _marker: PhantomData,
79	                }
80	            }
81	        }
82	    }
83	
84	    /// Calls the function.
85	    #[inline]
86	    pub(crate) fn call(mut self) {
87	        let call = self.call;
88	        unsafe { call(self.data.as_mut_ptr().cast::<u8>()) };
89	    }
90	}
