1	//! The default garbage collector.
2	//!
3	//! For each thread, a participant is lazily initialized on its first use, when the current thread
4	//! is registered in the default collector.  If initialized, the thread's participant will get
5	//! destructed on thread exit, which in turn unregisters the thread.
6	
7	#[cfg(not(crossbeam_loom))]
8	use std::sync::OnceLock;
9	
10	use crate::{
11	    collector::{Collector, LocalHandle},
12	    guard::Guard,
13	    primitive::thread_local,
14	};
15	
16	fn collector() -> &'static Collector {
17	    #[cfg(not(crossbeam_loom))]
18	    {
19	        /// The global data for the default garbage collector.
20	        static COLLECTOR: OnceLock<Collector> = OnceLock::new();
21	        COLLECTOR.get_or_init(Collector::new)
22	    }
23	    // FIXME: loom does not currently provide the equivalent of Lazy:
24	    // https://github.com/tokio-rs/loom/issues/263
25	    #[cfg(crossbeam_loom)]
26	    {
27	        loom::lazy_static! {
28	            /// The global data for the default garbage collector.
29	            static ref COLLECTOR: Collector = Collector::new();
30	        }
31	        &COLLECTOR
32	    }
33	}
