40	/// Pins the current thread.
41	#[inline]
42	pub fn pin() -> Guard {
43	    with_handle(|handle| handle.pin())
44	}
45	
46	/// Returns `true` if the current thread is pinned.
47	#[inline]
48	pub fn is_pinned() -> bool {
49	    with_handle(|handle| handle.is_pinned())
50	}
51	
52	/// Returns the default global collector.
53	pub fn default_collector() -> &'static Collector {
54	    collector()
55	}
