57	#[inline]
58	fn with_handle<F, R>(mut f: F) -> R
59	where
60	    F: FnMut(&LocalHandle) -> R,
61	{
62	    HANDLE
63	        .try_with(|h| f(h))
64	        .unwrap_or_else(|_| f(&collector().register()))
65	}
