75	
76	    #[test]
77	    fn pin_while_exiting() {
78	        struct Foo;
79	
80	        impl Drop for Foo {
81	            fn drop(&mut self) {
82	                // Pin after `HANDLE` has been dropped. This must not panic.
83	                super::pin();
84	            }
85	        }
86	
87	        std::thread_local! {
88	            static FOO: Foo = const { Foo };
89	        }
90	
91	        thread::scope(|scope| {
92	            scope.spawn(|_| {
93	                // Initialize `FOO` and then `HANDLE`.
94	                FOO.with(|_| ());
95	                super::pin();
96	                // At thread exit, `HANDLE` gets dropped first and `FOO` second.
97	            });
98	        })
99	        .unwrap();
100	    }
