183	/// Array with size.
184	///
185	/// # Memory layout
186	///
187	/// An array consisting of size and elements:
188	///
189	/// ```text
190	///          elements
191	///          |
192	///          |
193	/// ------------------------------------
194	/// | size | 0 | 1 | 2 | 3 | 4 | 5 | 6 |
195	/// ------------------------------------
196	/// ```
197	///
198	/// Its memory layout is different from that of `Box<[T]>` in that size is in the allocation (not
199	/// along with pointer as in `Box<[T]>`).
200	///
201	/// Elements are not present in the type, but they will be in the allocation.
202	#[repr(C)]
203	struct Array<T> {
204	    /// The number of elements (not the number of bytes).
205	    len: usize,
206	    elements: [MaybeUninit<T>; 0],
207	}
208	
209	impl<T> Array<T> {
210	    fn layout(len: usize) -> Layout {
211	        Layout::new::<Self>()
212	            .extend(Layout::array::<MaybeUninit<T>>(len).unwrap())
213	            .unwrap()
214	            .0
215	            .pad_to_align()
216	    }
217	}
218	
219	impl<T> Pointable for [MaybeUninit<T>] {
220	    const ALIGN: usize = mem::align_of::<Array<T>>();
221	
222	    type Init = usize;
223	
224	    #[inline]
225	    unsafe fn init(len: Self::Init) -> *mut () {
226	        let layout = Array::<T>::layout(len);
227	        match Global.allocate(layout) {
228	            Some(ptr) => unsafe {
229	                let ptr = ptr.as_ptr().cast::<Array<T>>();
230	                ptr::addr_of_mut!((*ptr).len).write(len);
231	                ptr.cast::<()>()
232	            },
233	            None => alloc::alloc::handle_alloc_error(layout),
234	        }
235	    }
236	
237	    unsafe fn as_ptr(ptr: *mut ()) -> *const Self {
238	        unsafe {
239	            let len = (*ptr.cast::<Array<T>>()).len;
240	            // Use addr_of_mut for stacked borrows: https://github.com/rust-lang/miri/issues/1976
241	            let elements =
242	                ptr::addr_of_mut!((*ptr.cast::<Array<T>>()).elements).cast::<MaybeUninit<T>>();
243	            ptr::slice_from_raw_parts(elements, len)
244	        }
245	    }
246	
247	    unsafe fn as_mut_ptr(ptr: *mut ()) -> *mut Self {
248	        unsafe {
249	            let len = (*ptr.cast::<Array<T>>()).len;
250	            let elements =
251	                ptr::addr_of_mut!((*ptr.cast::<Array<T>>()).elements).cast::<MaybeUninit<T>>();
252	            ptr::slice_from_raw_parts_mut(elements, len)
253	        }
254	    }
255	
256	    unsafe fn drop(ptr: *mut ()) {
257	        unsafe {
258	            let len = (*ptr.cast::<Array<T>>()).len;
259	            let layout = Array::<T>::layout(len);
260	            Global.deallocate(NonNull::new_unchecked(ptr.cast::<u8>()), layout);
261	        }
262	    }
263	}
