321	    const_fn! {
322	        const_if: #[cfg(not(crossbeam_loom))];
323	        /// Returns a new null atomic pointer.
324	        ///
325	        /// # Examples
326	        ///
327	        /// ```
328	        /// use crossbeam_epoch::Atomic;
329	        ///
330	        /// let a = Atomic::<i32>::null();
331	        /// ```
332	        pub const fn null() -> Self {
333	            Self {
334	                data: AtomicPtr::new(ptr::null_mut()),
335	                _marker: PhantomData,
336	            }
