340	    /// Loads a `Shared` from the atomic pointer.
341	    ///
342	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
343	    /// operation.
344	    ///
345	    /// # Examples
346	    ///
347	    /// ```
348	    /// use crossbeam_epoch::{self as epoch, Atomic};
349	    /// use std::sync::atomic::Ordering::SeqCst;
350	    ///
351	    /// let a = Atomic::new(1234);
352	    /// let guard = &epoch::pin();
353	    /// let p = a.load(SeqCst, guard);
354	    /// # unsafe { drop(a.into_owned()); } // avoid leak
355	    /// ```
356	    pub fn load<'g>(&self, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
357	        unsafe { Shared::from_ptr(self.data.load(order)) }
