360	    /// Loads a `Shared` from the atomic pointer using a "consume" memory ordering.
361	    ///
362	    /// This is similar to the "acquire" ordering, except that an ordering is
363	    /// only guaranteed with operations that "depend on" the result of the load.
364	    /// However consume loads are usually much faster than acquire loads on
365	    /// architectures with a weak memory model since they don't require memory
366	    /// fence instructions.
367	    ///
368	    /// The exact definition of "depend on" is a bit vague, but it works as you
369	    /// would expect in practice since a lot of software, especially the Linux
370	    /// kernel, rely on this behavior.
371	    ///
372	    /// # Examples
373	    ///
374	    /// ```
375	    /// use crossbeam_epoch::{self as epoch, Atomic};
376	    ///
377	    /// let a = Atomic::new(1234);
378	    /// let guard = &epoch::pin();
379	    /// let p = a.load_consume(guard);
380	    /// # unsafe { drop(a.into_owned()); } // avoid leak
381	    /// ```
382	    pub fn load_consume<'g>(&self, _: &'g Guard) -> Shared<'g, T> {
383	        unsafe { Shared::from_ptr(self.data.load_consume()) }
384	    }
