386	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer.
387	    ///
388	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
389	    /// operation.
390	    ///
391	    /// # Examples
392	    ///
393	    /// ```
394	    /// use crossbeam_epoch::{Atomic, Owned, Shared};
395	    /// use std::sync::atomic::Ordering::SeqCst;
396	    ///
397	    /// let a = Atomic::new(1234);
398	    /// # unsafe { drop(a.load(SeqCst, &crossbeam_epoch::pin()).into_owned()); } // avoid leak
399	    /// a.store(Shared::null(), SeqCst);
400	    /// a.store(Owned::new(1234), SeqCst);
401	    /// # unsafe { drop(a.into_owned()); } // avoid leak
402	    /// ```
403	    pub fn store<P: Pointer<T>>(&self, new: P, order: Ordering) {
404	        self.data.store(new.into_ptr(), order);
405	    }
