407	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer, returning the previous
408	    /// `Shared`.
409	    ///
410	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
411	    /// operation.
412	    ///
413	    /// # Examples
414	    ///
415	    /// ```
416	    /// use crossbeam_epoch::{self as epoch, Atomic, Shared};
417	    /// use std::sync::atomic::Ordering::SeqCst;
418	    ///
419	    /// let a = Atomic::new(1234);
420	    /// let guard = &epoch::pin();
421	    /// let p = a.swap(Shared::null(), SeqCst, guard);
422	    /// # unsafe { drop(p.into_owned()); } // avoid leak
423	    /// ```
424	    pub fn swap<'g, P: Pointer<T>>(&self, new: P, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
425	        unsafe { Shared::from_ptr(self.data.swap(new.into_ptr(), order)) }
426	    }
