428	    /// Stores the pointer `new` (either `Shared` or `Owned`) into the atomic pointer if the current
429	    /// value is the same as `current`. The tag is also taken into account, so two pointers to the
430	    /// same object, but with different tags, will not be considered equal.
431	    ///
432	    /// The return value contains both the previous value and the new value that was written.
433	    /// On success, `old` contains the previous value (which equals `current`) and `new` contains
434	    /// the value that was stored. On failure, `old` contains the actual current value and `new`
435	    /// contains the value that was attempted to be stored.
436	    ///
437	    /// This method takes two `Ordering` arguments to describe the memory
438	    /// ordering of this operation. `success` describes the required ordering for the
439	    /// read-modify-write operation that takes place if the comparison with `current` succeeds.
440	    /// `failure` describes the required ordering for the load operation that takes place when
441	    /// the comparison fails. Using `Acquire` as success ordering makes the store part
442	    /// of this operation `Relaxed`, and using `Release` makes the successful load
443	    /// `Relaxed`. The failure ordering can only be `SeqCst`, `Acquire` or `Relaxed`
444	    /// and must be equivalent to or weaker than the success ordering.
445	    ///
446	    /// # Examples
447	    ///
448	    /// ```
449	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned, Shared};
450	    /// use std::sync::atomic::Ordering::SeqCst;
451	    ///
452	    /// let a = Atomic::new(1234);
453	    ///
454	    /// let guard = &epoch::pin();
455	    /// let curr = a.load(SeqCst, guard);
456	    /// let res1 = a.compare_exchange(curr, Shared::null(), SeqCst, SeqCst, guard);
457	    /// let res2 = a.compare_exchange(curr, Owned::new(5678), SeqCst, SeqCst, guard);
458	    /// # unsafe { drop(curr.into_owned()); } // avoid leak
459	    /// ```
460	    pub fn compare_exchange<'g, P>(
461	        &self,
462	        current: Shared<'_, T>,
463	        new: P,
464	        success: Ordering,
465	        failure: Ordering,
466	        _: &'g Guard,
467	    ) -> Result<CompareExchangeValue<'g, T>, CompareExchangeError<'g, T, P>>
468	    where
469	        P: Pointer<T>,
470	    {
471	        let new = new.into_ptr();
472	        self.data
473	            .compare_exchange(current.into_ptr(), new, success, failure)
474	            .map(|old| unsafe {
475	                CompareExchangeValue {
476	                    old: Shared::from_ptr(old),
477	                    new: Shared::from_ptr(new),
478	                }
479	            })
480	            .map_err(|current| unsafe {
481	                CompareExchangeError {
482	                    current: Shared::from_ptr(current),
483	                    new: P::from_ptr(new),
484	                }
485	            })
486	    }
