488	    /// Stores the pointer `new` (either `Shared` or `Owned`) into the atomic pointer if the current
489	    /// value is the same as `current`. The tag is also taken into account, so two pointers to the
490	    /// same object, but with different tags, will not be considered equal.
491	    ///
492	    /// Unlike [`compare_exchange`], this method is allowed to spuriously fail even when comparison
493	    /// succeeds, which can result in more efficient code on some platforms. The return value
494	    /// contains both the previous value and the new value that was written. On success, `old`
495	    /// contains the previous value (which equals `current`) and `new` contains the value that was
496	    /// stored. On failure, `old` contains the actual current value and `new` contains the value
497	    /// that was attempted to be stored.
498	    ///
499	    /// This method takes two `Ordering` arguments to describe the memory
500	    /// ordering of this operation. `success` describes the required ordering for the
501	    /// read-modify-write operation that takes place if the comparison with `current` succeeds.
502	    /// `failure` describes the required ordering for the load operation that takes place when
503	    /// the comparison fails. Using `Acquire` as success ordering makes the store part
504	    /// of this operation `Relaxed`, and using `Release` makes the successful load
505	    /// `Relaxed`. The failure ordering can only be `SeqCst`, `Acquire` or `Relaxed`
506	    /// and must be equivalent to or weaker than the success ordering.
507	    ///
508	    /// [`compare_exchange`]: Atomic::compare_exchange
509	    ///
510	    /// # Examples
511	    ///
512	    /// ```
513	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned, Shared};
514	    /// use std::sync::atomic::Ordering::SeqCst;
515	    ///
516	    /// let a = Atomic::new(1234);
517	    /// let guard = &epoch::pin();
518	    ///
519	    /// let mut new = Owned::new(5678);
520	    /// let mut ptr = a.load(SeqCst, guard);
521	    /// # unsafe { drop(a.load(SeqCst, guard).into_owned()); } // avoid leak
522	    /// loop {
523	    ///     match a.compare_exchange_weak(ptr, new, SeqCst, SeqCst, guard) {
524	    ///         Ok(result) => {
525	    ///             ptr = result.old;
526	    ///             break;
527	    ///         }
528	    ///         Err(err) => {
529	    ///             ptr = err.current;
530	    ///             new = err.new;
531	    ///         }
532	    ///     }
533	    /// }
534	    ///
535	    /// let mut curr = a.load(SeqCst, guard);
536	    /// loop {
537	    ///     match a.compare_exchange_weak(curr, Shared::null(), SeqCst, SeqCst, guard) {
538	    ///         Ok(_) => break,
539	    ///         Err(err) => curr = err.current,
540	    ///     }
541	    /// }
542	    /// # unsafe { drop(curr.into_owned()); } // avoid leak
543	    /// ```
544	    pub fn compare_exchange_weak<'g, P>(
545	        &self,
546	        current: Shared<'_, T>,
547	        new: P,
548	        success: Ordering,
549	        failure: Ordering,
550	        _: &'g Guard,
551	    ) -> Result<CompareExchangeValue<'g, T>, CompareExchangeError<'g, T, P>>
552	    where
553	        P: Pointer<T>,
554	    {
555	        let new = new.into_ptr();
556	        self.data
557	            .compare_exchange_weak(current.into_ptr(), new, success, failure)
558	            .map(|old| unsafe {
559	                CompareExchangeValue {
560	                    old: Shared::from_ptr(old),
561	                    new: Shared::from_ptr(new),
562	                }
563	            })
564	            .map_err(|current| unsafe {
565	                CompareExchangeError {
566	                    current: Shared::from_ptr(current),
567	                    new: P::from_ptr(new),
568	                }
569	            })
570	    }
